```javascript
class LRUCache {
    constructor(capacity) {
        this.capacity = capacity;
        this.cache = new Map();
        this.head = { key: 0, value: 0 };
        this.tail = { key: 0, value: 0 };
        this.connect(this.head, this.tail);
    }

    connect(prev, next) {
        prev.next = next;
        next.prev = prev;
    }

    get(key) {
        if (!this.cache.has(key)) return -1;
        const node = this.cache.get(key);
        this.moveToHead(node);
        return node.value;
    }

    put(key, value) {
        if (this.cache.has(key)) {
            const node = this.cache.get(key);
            node.value = value;
            this.moveToHead(node);
            return;
        }
        if (this.cache.size === this.capacity) {
            const tailNode = this.tail.prev;
            this.removeNode(tailNode);
            this.cache.delete(tailNode.key);
        }
        const newNode = { key, value };
        this.cache.set(key, newNode);
        this.moveToHead(newNode);
    }

    moveToHead(node) {
        this.removeNode(node);
        this.connect(this.head, node);
        this.connect(node, this.head.next);
    }

    removeNode(node) {
        node.prev.next = node.next;
        node.next.prev = node.prev;
    }
}

// Test code
const cache = new LRUCache(2);
cache.put(1, 1);
cache.put(2, 2);
console.log(cache.get(1)); // Output: 1
cache.put(3, 3); // Evicts key 2
console.log(cache.get(2)); // Output: -1
cache.put(4, 4); // Evicts key 1
console.log(cache.get(1)); // Output: -1
console.log(cache.get(3)); // Output: 3
console.log(cache.get(4)); // Output: 4
```

```javascript
async function retry(fn, maxRetries, delayMs) {
  for (let i = 0; i <= maxRetries; i++) {
    try {
      return await fn();
    } catch (error) {
      if (i === maxRetries) throw error;
      await new Promise(resolve => setTimeout(resolve, delayMs * Math.pow(2, i)));
    }
  }
}

// Test function
