  let attempts = 0;

  const failingFunction = async () => {
    attempts++;
    if (attempts < 3) throw new Error('Failed');
    return 'Success';
  };

  try {
    const result = await retry(failingFunction, 3, 100);
    console.log(`Result: ${result}`);
    console.log(`Attempts made: ${attempts}`);
  } catch (error) {
    console.error(`Error after all retries: ${error.message}`);
  }
}

testRetry();
```

