```javascript
class Router {
  constructor() {
    this.routes = {};
  }

  add(method, pattern, handler) {
    if (!this.routes[method]) {
      this.routes[method] = [];
    }
    this.routes[method].push({
      pattern,
      handler,
      regex: this.compilePattern(pattern)
    });
  }

  match(method, path) {
    if (this.routes[method]) {
      for (const route of this.routes[method]) {
        const match = path.match(route.regex);
        if (match) {
          return {
            handler: route.handler,
            params: this.parseParams(route.pattern, match)
          };
        }
      }
    }
    return null;
  }

  compilePattern(pattern) {
    return new RegExp(
      '^' +
      pattern.replace(/\/\:[^\/*]+/g, (match) => `([^\\/]+)`).replace(/\//g, '\\/') +
      '$'
    );
  }

  parseParams(pattern, match) {
    const params = {};
    let i = 1;
    pattern.split('/').forEach(segment => {
      if (segment.startsWith(':')) {
        params[segment.slice(1)] = decodeURIComponent(match[i++]);
      }
    });
    return params;
  }
}

