    println!("{}", longest_common_prefix(&["dog", "racecar", "car"])); // Output: ""
    println!("{}", longest_common_prefix(&["interspecies", "interstellar", "interstate"])); // Output: "inters"
    println!("{}", longest_common_prefix(&["alone"])); // Output: "alone"
    println!("'{}'", longest_common_prefix(&[])); // Output: ""
