use std::fmt::{Display, Formatter, Result};

struct Stack<T> {
    items: Vec<T>,
}

impl<T> Stack<T> {
    fn new() -> Stack<T> {
        Stack { items: Vec::new() }
    }

    fn push(&mut self, item: T) {
        self.items.push(item);
    }

    fn pop(&mut self) -> Option<T> {
        self.items.pop()
    }

    fn peek(&self) -> Option<&T> {
        self.items.last()
    }

    fn is_empty(&self) -> bool {
        self.items.is_empty()
    }

    fn len(&self) -> usize {
        self.items.len()
    }
}

impl<T: Display> Display for Stack<T> {
    fn fmt(&self, f: &mut Formatter<'_>) -> Result {
        let items = self
            .items
            .iter()
            .map(|item| item.to_string())
            .collect::<Vec<_>>()
            .join(" -> ");
        write!(f, "{}", items)
    }
}

fn main() {
    let mut int_stack = Stack::new();
    int_stack.push(1);
    int_stack.push(2);
    int_stack.push(3);

    println!("Int stack: {}", int_stack); // 3 -> 2 -> 1
    println!("Peeked: {:?}", int_stack.peek()); // Some(3)
    println!("Popped: {:?}", int_stack.pop()); // Some(3)

    let mut str_stack = Stack::new();
    str_stack.push("apple".to_string());
    str_stack.push("banana".to_string());
    str_stack.push("cherry".to_string());

    println!("Str stack: {}", str_stack); // cherry -> banana -> apple
    println!("Peeked: {:?}", str_stack.peek()); // Some("cherry")
    println!("Popped: {:?}", str_stack.pop()); // Some("cherry")

    println!("Int stack is empty: {}", int_stack.is_empty()); // false
    println!("Str stack length: {}", str_stack.len()); // 2

    while !str_stack.is_empty() {
        println!("Popped: {:?}", str_stack.pop());
    }

    println!("Str stack is empty: {}", str_stack.is_empty()); // true
}
