use std::collections::HashMap;
use std::collections::VecDeque;

fn validate_brackets(s: &str) -> bool {
    let mut stack = VecDeque::new();
    let bracket_pairs: HashMap<char, char> = [ 
        ('(', ')'), 
        ('[', ']'), 
        ('{', '}') 
    ].iter().cloned().collect();

    for c in s.chars() {
        if bracket_pairs.contains_key(&c) {
            stack.push_back(c);
        } else if let Some(opening_bracket) = stack.pop_back() {
            if bracket_pairs[&opening_bracket] != c {
                return false;
            }
        }
    }

    stack.is_empty()
}

fn main() {
    println!("{}", validate_brackets("()"));           // true
    println!("{}", validate_brackets("()[]{}"));       // true
    println!("{}", validate_brackets("(]"));           // false
    println!("{}", validate_brackets("([)]"));         // false
    println!("{}", validate_brackets("{[]}"));         // true
    println!("{}", validate_brackets(""));             // true
    println!("{}", validate_brackets("let x = arr[func(i)];"));  // true
    println!("{}", validate_brackets("((("));          // false
}
