```javascript
const WebSocket = require('ws')
const { randomUUID } = require('crypto')
const cliManager = require('./cliManager') // Assume this is already implemented

// Pending request tracking
const pendingAskUser = new Map()    // id → { resolve, createdAt }
const pendingToolConfirm = new Map() // id → { resolve, createdAt }

// WebSocket to requestId mapping for chat events
const cliRequestToWs = new WeakMap() // ws → requestId

// Create a WebSocket server
const wss = new WebSocket.Server({ port: 8080 })

wss.on('connection', (ws) => {
  ws.on('message', async (raw) => {
    let msg
    try {
      msg = JSON.parse(raw)
    } catch {
      ws.send(JSON.stringify({ type: 'error', error: 'Invalid JSON' }))
      return
    }

    switch (msg.type) {
      case 'chat': {
        const requestId = randomUUID()
        cliRequestToWs.set(ws, requestId)

        try {
          await cliManager.chat({
            prompt: msg.prompt,
            model: msg.model,
            sessionId: msg.sessionId
          }, {
            onEvent: (event) => {
              if (ws.readyState === WebSocket.OPEN) {
                ws.send(JSON.stringify(event))
              }
            },
            onComplete: () => {
              cliRequestToWs.delete(ws)
            }
          })
        } catch (error) {
          ws.send(JSON.stringify({ type: 'error', error: error.message }))
        }
        break
      }

      case 'ask_user_response': {
        const entry = pendingAskUser.get(msg.id)
        if (entry && (Date.now() - entry.createdAt < 60000)) { // Timeout after 1 minute
          entry.resolve(msg.response)
          pendingAskUser.delete(msg.id)
        } else {
          ws.send(JSON.stringify({ type: 'error', error: 'Invalid or expired ask_user response' }))
        }
        break
      }

      case 'tool_confirm_response': {
        const entry = pendingToolConfirm.get(msg.id)
        if (entry && (Date.now() - entry.createdAt < 60000)) { // Timeout after 1 minute
          entry.resolve(msg.response)
          pendingToolConfirm.delete(msg.id)
        } else {
          ws.send(JSON.stringify({ type: 'error', error: 'Invalid or expired tool confirmation response' }))
        }
        break
      }

      default:
        ws.send(JSON.stringify({ type: 'error', error: 'Unknown message type' }))
    }
  })

  ws.on('close', () => {
    const requestId = cliRequestToWs.get(ws)
    if (requestId) {
      // Notify the CLI manager to cancel any associated request
      cliManager.cancelChat(requestId)
      cliRequestToWs.delete(ws)
    }
  })
