Here's a basic implementation of the `ClaudeCliManager` class in Node.js:

```javascript
const { spawn } = require('child_process');
const path = require('path');
const os = require('os');
const { v4: uuidv4 } = require('uuid');

class ClaudeCliManager {
  constructor(mcpProxyPort = null) {
    this.mcpProxyPort = mcpProxyPort;
    this.processes = new Map();
  }

  async chat({ prompt, model, sessionId, systemPrompt, cwd }, onEvent) {
    const requestId = uuidv4();

    let args = ['--output-format', 'stream-json', '--verbose'];

    if (sessionId) {
      args.push('--resume', sessionId);
    } else {
      const newId = `session_${requestId}`;
      args.push('--session-id', newId);
      if (model) args.push('--model', model);
      if (systemPrompt) args.push('--append-system-prompt');
    }

    if (this.mcpProxyPort) {
      const mcpConfigPath = path.join(os.tmpdir(), `mcp_config_${requestId}.json`);
      const mcpConfigContent = JSON.stringify({
        mcpServers: {
          paloma: {
            type: 'sse',
            url: `http://localhost:${this.mcpProxyPort}/sse`,
          },
        },
      });
      await this.writeTempFile(mcpConfigPath, mcpConfigContent);
      args.push('--mcp-config', mcpConfigPath, '--allowedTools', 'mcp__paloma__*');
    }

    const process = spawn('claude', args, { stdio: ['ignore', 'pipe', 'pipe'], cwd });

    process.stdout.on('data', (data) => {
      data.toString().split('\n').forEach(line => {
        try {
          const parsed = JSON.parse(line);
          onEvent(parsed);
        } catch {}
      });
    });

    process.stderr.on('data', (data) => console.error(data));

    process.on('close', () => {
      if (mcpConfigPath) this.deleteTempFile(mcpConfigPath);
      this.processes.delete(requestId);
    });

    this.processes.set(requestId, { process, sessionId, mcpConfigPath });
    return { requestId, sessionId };
  }

  stop(requestId) {
    const entry = this.processes.get(requestId);
    if (!entry) return;
    entry.process.kill();
    if (entry.mcpConfigPath) this.deleteTempFile(entry.mcpConfigPath);
    this.processes.delete(requestId);
  }

  cleanup() {
    for (const [requestId, { process, mcpConfigPath }] of this.processes.entries()) {
      process.kill();
      if (mcpConfigPath) this.deleteTempFile(mcpConfigPath);
      this.processes.delete(requestId);
    }
  }

  async writeTempFile(filePath, content) {
    return new Promise((resolve, reject) => {
      const fs = require('fs');
      fs.writeFile(filePath, content, 'utf8', (err) => err ? reject(err) : resolve());
    });
  }

  deleteTempFile(filePath) {
    const fs = require('fs');
    try {
      fs.unlinkSync(filePath);
    } catch {}
  }
}

module.exports = ClaudeCliManager;
```

This class uses `child_process.spawn` to spawn the `claude` subprocess and manages its lifecycle, including tracking process IDs, handling stdout parsing, and cleaning up resources. The MCP config file is created temporarily in the OS's temporary directory and deleted when no longer needed.

